use crate::engine::FrfProducer;

pub struct RangeProducer {
    pub start: usize,
    pub end: usize,
}

impl FrfProducer for RangeProducer {
    type Item = usize;
    type Iter = std::ops::Range<usize>;

    fn len(&self) -> usize {
        self.end.saturating_sub(self.start)
    }

    fn split_at(self, index: usize) -> (Self, Self) {
        let mid = std::cmp::min(self.start + index, self.end);
        (
            RangeProducer {
                start: self.start,
                end: mid,
            },
            RangeProducer {
                start: mid,
                end: self.end,
            },
        )
    }

    fn into_iter(self) -> Self::Iter {
        self.start..self.end
    }
}
